    if (k >= (n - 1) || k >= (m - 1)) {
        return 1;
    }

    // Calculate the number of sensors needed
    int64_t rows = (n + 2 * k - 1) / (2 * k);
    int64_t cols = (m + 2 * k - 1) / (2 * k);
